//-------------------------------------------------------------------------
// BL/BK 검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openBlBkNoPopUp = async function () {
    var param = { "blBkNo": ed_blBkNo.getValue() };

    var options = {
        id: "pupup",
        popupName: "BL/BK검색팝업",
        type: "browserPopup",
        modal: true,
        width: 1000,
        height: 605
    }

    var rtnValues = await $c.win.openPopup("/ui/to/in/bulk/tmlbulk/in_201_02_04p.xml", options, param);

    if (!$c.gus.cfIsNull(rtnValues)) {
        ed_blBkNo.setValue(rtnValues[12]);
    }
    else {
        ed_blBkNo.setValue("");
    }
};

//-------------------------------------------------------------------------
// 본선관리번호검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openCvsslMgntNoPopUp = async function () {
    var param = [ed_cvsslMgntNo.getValue()];

    var options = {
        id: "pupup",
        popupName: "본선관리번호검색팝업",
        type: "browserPopup",
        modal: true,
        width: 885,
        height: 500
    }

    var rtnValues = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", options, param);

    if (!$c.gus.cfIsNull(rtnValues)) {
        ed_cvsslMgntNo.setValue(rtnValues[0]);
    }
    else {
        ed_cvsslMgntNo.setValue("");
    }
};

//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
    totCnt = ds_retrieveWrkPlan.getRowCount();

    if (totCnt != 0) {
        cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            var options = {
                fileName: "벌크 작업 지시 정보.xlsx",
                sheetName: "벌크 작업 지시 정보",
                startRowIndex: 0,
                startColumnIndex: 0,
                type: 1
            };

            //cfGridToExcel(varGrNm, sheetTitle, sheetTitle + ".xls", 4 + 8 + 16);
            $c.data.downloadGridViewExcel(gr_retrieveWrkPlan, options);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

